proof_block:
// Bridge the trigger gap between the two ensures-copies (one for r1 /
// post1_self_, one for r2 / post2_self_) by re-instantiating each
// `forall` ensures with explicit triggers tied to BOTH `post1_self_`
// and `post2_self_`.  Every assertion is a direct restatement of an
// ensures conjunct from the synthetic proof fn — Verus discharges it
// from the existing ensures, with no further hints.

// --- proc_dom is preserved on both runs ----------------------------------
assert(post1_self_.proc_dom() == pre_self_.proc_dom());
assert(post2_self_.proc_dom() == pre_self_.proc_dom());

// --- thread_dom / endpoint_dom / container_dom preserved -----------------
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());

// --- forall procs: get_proc preserved on both runs ------------------------
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger pre_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
        ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    #![trigger pre_self_.get_proc(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr)
        ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

// --- forall threads ------------------------------------------------------
assert(forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger pre_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr)
        ==> post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger post2_self_.get_thread(t_ptr)]
    #![trigger pre_self_.get_thread(t_ptr)]
    post2_self_.thread_dom().contains(t_ptr)
        ==> post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));

// --- forall endpoints ----------------------------------------------------
assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger pre_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr)
        ==> post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    #![trigger pre_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr)
        ==> post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));

// --- forall containers != owning_container -------------------------------
let owning_c: ContainerPtr = pre_self_.get_proc(target_proc_ptr).owning_container;
assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger pre_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != owning_c
        ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
            && post1_self_.get_container_owned_pages(c_ptr)
                =~= pre_self_.get_container_owned_pages(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    #![trigger pre_self_.get_container(c_ptr)]
    post2_self_.container_dom().contains(c_ptr) && c_ptr != owning_c
        ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr)
            && post2_self_.get_container_owned_pages(c_ptr)
                =~= pre_self_.get_container_owned_pages(c_ptr));

// --- forall procs != target: address space preserved ---------------------
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_address_space(p_ptr)]
    #![trigger pre_self_.get_address_space(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post1_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_address_space(p_ptr)]
    #![trigger pre_self_.get_address_space(p_ptr)]
    post2_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post2_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));

// --- forall Pcid: pcid_to_proc_ptr preserved on active pcids --------------
assert(forall|p: Pcid|
    #![trigger post1_self_.mem_man.pcid_active(p)]
    #![trigger post1_self_.mem_man.pcid_to_proc_ptr(p)]
    post1_self_.mem_man.pcid_active(p)
        ==> pre_self_.mem_man.pcid_to_proc_ptr(p)
            == post1_self_.mem_man.pcid_to_proc_ptr(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.mem_man.pcid_active(p)]
    #![trigger post2_self_.mem_man.pcid_to_proc_ptr(p)]
    post2_self_.mem_man.pcid_active(p)
        ==> pre_self_.mem_man.pcid_to_proc_ptr(p)
            == post2_self_.mem_man.pcid_to_proc_ptr(p));

// --- forall pages: page_is_mapped preserved off ret.addr ------------------
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    p != r1.addr ==> post1_self_.page_alloc.page_is_mapped(p)
        == pre_self_.page_alloc.page_is_mapped(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    p != r2.addr ==> post2_self_.page_alloc.page_is_mapped(p)
        == pre_self_.page_alloc.page_is_mapped(p));

// --- forall pages: page_mapping preserved on pre-domain -------------------
assert(forall|page_ptr: PagePtr|
    #![trigger post1_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr)
        ==> pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]);
assert(forall|page_ptr: PagePtr|
    #![trigger post2_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr)
        ==> pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]);

// --- domains of page_mapping are insertions of ret.addr -------------------
assert(post1_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom().insert(r1.addr));
assert(post2_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom().insert(r2.addr));

// --- address-space update at target_proc_ptr -----------------------------
assert(post1_self_.get_address_space(target_proc_ptr)
    =~= pre_self_.get_address_space(target_proc_ptr).insert(target_va, r1));
assert(post2_self_.get_address_space(target_proc_ptr)
    =~= pre_self_.get_address_space(target_proc_ptr).insert(target_va, r2));

// --- container-quota subtract relation on owning_container ---------------
assert(pre_self_.get_container(owning_c).quota.spec_subtract_mem_4k(
    post1_self_.get_container(owning_c).quota, 1));
assert(pre_self_.get_container(owning_c).quota.spec_subtract_mem_4k(
    post2_self_.get_container(owning_c).quota, 1));

// --- num-of-free-pages decrement is the same on both runs ----------------
assert(post1_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - 1);
assert(post2_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - 1);
assert(post1_self_.get_num_of_free_pages() == post2_self_.get_num_of_free_pages());

// --- final view-level equalities forced by Set / Map extensionality ------
assert(post1_self_.page_mapping@.dom() =~= post2_self_.page_mapping@.dom()
    <==> r1.addr == r2.addr);

// Pointwise equality of the page_mapping views off the newly-inserted page.
assert forall|p: PagePtr|
    pre_self_.page_mapping@.dom().contains(p)
    implies post1_self_.page_mapping@[p] == post2_self_.page_mapping@[p]
by {
    // Each side equals pre_self_.page_mapping@[p] by the respective
    // pulled-up forall above, so they agree by transitivity.
}
